  ('elementary-c5fb3965-moex-00194', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-55d283b0', 'sub-elementary-c5fb3965-04', NULL, 'single_choice', '甲欲殺乙，誤丙為乙而殺之，屬於何種錯誤型態？', '["因果歷程錯誤", "等價的客體錯誤", "打擊錯誤", "包攝錯誤"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:06+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
