  ('elementary-d0d1b9a2-moex-00004', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-b3f42868', 'sub-elementary-d0d1b9a2-01', NULL, 'single_choice', '對社會而言，下列那一種財貨或服務的機會成本最低？', '["政府提供的免費服務", "不具相對稀少性的物品", "準備拿來當作肥料的雞糞", "無法提升消費者效用的物品"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
